# Load businesses and reviews
businesses = locals()['var_functions.query_db:30']

with open('file_storage/functions.query_db:48.json', 'r') as f:
    reviews = json.load(f)

# Parse categories with safer method
credit_business_cats = {}

for biz in businesses:
    bid = biz['business_id']
    bref = bid.replace('businessid_', 'businessref_')
    desc = biz.get('description', '')

    categories = []
    # Find category list using position-based parsing
    if 'services' in desc.lower():
        # Look for the part after 'services' and before period
        parts = desc.split('.')
        for part in parts:
            if 'services' in part.lower():
                # Extract text after services keyword
                temp = part
                for keyword in ['services in ', 'services, including ', 'services including ']:
                    if keyword in temp:
                        temp = temp.split(keyword)[1]
                        categories = [c.strip() for c in temp.split(',')]
                        break
                break

    # Clean categories
    clean_cats = []
    for cat in categories:
        clean = cat.strip(" '")
        if clean and len(clean) < 40:
            clean_cats.append(clean)

    if clean_cats:
        credit_business_cats[bref] = clean_cats

# Count businesses per category
from collections import defaultdict
cat_counts = defaultdict(int)

for bref, cats in credit_business_cats.items():
    for cat in cats:
        cat_counts[cat] += 1

# Find top category
top_category = max(cat_counts.items(), key=lambda x: x[1]) if cat_counts else (None, 0)

# Get average rating for top category businesses
if top_category[0]:
    target_brefs = [b for b, cats in credit_business_cats.items() if top_category[0] in cats]

    ratings = []
    for review in reviews:
        if review['business_ref'] in target_brefs:
            ratings.append(int(review['rating']))

    avg_rating = sum(ratings) / len(ratings) if ratings else 0

    result = {
        'top_category': top_category[0],
        'business_count': top_category[1],
        'avg_rating': round(avg_rating, 2),
        'total_reviews': len(ratings)
    }
else:
    result = {'error': 'Could not determine top category'}

print('__RESULT__:')
